#include <stdio.h>
#include <stdint.h>

static inline uint64_t xor_upto(long long n) {
    if (n < 0) return 0ULL;
    switch (n & 3LL) { // n % 4
        case 0: return (uint64_t)n;
        case 1: return 1ULL;
        case 2: return (uint64_t)n + 1ULL;
        default: return 0ULL; // case 3
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        uint64_t ans = xor_upto(R) ^ xor_upto(L - 1);
        printf("%llu\n", ans);
    }
    return 0;
}

